#include<cstdio>
#include<vector>
#include<algorithm>
#include<map>
#include<queue>
#include<cstring>
#include<cmath>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char c=0,ch=getchar();while(ch<'0'||ch>'9')c=ch,ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return c=='-'?-res:res;
}
const double g=9.8;const int N=5e5+10;
map<int,vector<int>> op,qy;int n,x[N],y[N],v[N];
double tmp[N],P[N];int p,ans[N],t[N],ord[N],nxt[N];
priority_queue<int> h;
inline int bnd(double x){int l(0),r(p-1),m;while(l<=r)P[m=(l+r)>>1]<=x?l=m+1:r=m-1;return l-1;}
inline void add(int x){++x;while(x<=p)++t[x],x+=(x&-x);}
inline int qry(int x){++x;int r=0;while(x)r+=t[x],x^=(x&-x);return r;}
inline void Solve(int y,vector<int> &a)
{
//	printf("Solve %d\n",y);
	qy.clear();for(int i:a)qy[x[i]].push_back(i);
	double T=sqrt(2.*y/g);for(unsigned i=0;i<a.size();++i)tmp[i]=P[i]=1.*v[a[i]]*T+x[a[i]];
	sort(P,P+a.size());p=unique(P,P+a.size())-P;
	
	memset(t+1,0,p*sizeof(int));
	for(unsigned i=0;i<a.size();++i)nxt[a[i]]=bnd(tmp[i]);
//	rep(1,n,i)printf("%d ",nxt[i]);puts("");
	for(pair<int,vector<int>> b:qy)
	{
		for(int i:b.second)ans[i]+=qry(p-1)-qry(nxt[i]-1);
		for(int i:b.second)add(nxt[i]);
	}
	memset(t+1,0,p*sizeof(int));
	map<int,vector<int>> :: iterator it=qy.end();
	while(it!=qy.begin())
	{
		--it;vector<int> &b=it->second;
		for(int i:b)ans[i]+=qry(nxt[i])+b.size()-1;
		for(int i:b)add(nxt[i]); 
	}
}
int main()
{
	n=read();int m=read();rep(1,n,i)x[i]=read(),y[i]=read(),v[i]=read(),op[y[i]].push_back(i);
	for(pair<int,vector<int>> v:op)Solve(v.first,v.second);rep(1,n,i)h.push(min(read(),ans[i]));
//	rep(1,n,i)printf("%d ",ans[i]);puts("");
	long long sum=0;rep(1,n,i)sum+=ans[i];while(!h.empty()&&m--)sum-=h.top(),h.pop();
	printf("%lld\n",sum);return 0;
}
